import React, { useEffect, useState } from 'react';
import api from '../api'; // Siguroha nga husto ang path padulong sa api.ts
import PatientCard from './PatientCard'; // Gi-tangtang ang { } kay default export ni

const PatientList = () => {
    const [patients, setPatients] = useState([]);

    useEffect(() => {
        api.get('patients/')
            .then(res => setPatients(res.data))
            .catch(err => console.error("Error fetching patients:", err));
    }, []);

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {patients.map((p: any) => (
                <PatientCard 
                    key={p.patient_id} 
                    patient={p} 
                    onEdit={() => console.log('Edit', p.patient_id)}
                    onDelete={() => console.log('Delete', p.patient_id)}
                />
            ))}
        </div>
    );
};

export default PatientList;
